import{_ as o,o as a,c as t,ag as r}from"./chunks/framework.CbQjVMS6.js";const p=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"PaiSmart/面试/各类杂项问题.md","filePath":"PaiSmart/面试/各类杂项问题.md","lastUpdated":null}'),s={name:"PaiSmart/面试/各类杂项问题.md"};function n(c,e,d,_,i,l){return a(),t("div",null,[...e[0]||(e[0]=[r('<h2 id="配置环境时遇到的问题" tabindex="-1">配置环境时遇到的问题 <a class="header-anchor" href="#配置环境时遇到的问题" aria-label="Permalink to &quot;配置环境时遇到的问题&quot;">​</a></h2><ul><li>“在本地搭建环境时，我遇到了 Windows 环境下 Kafka 独特的 <strong>mmap 文件句柄锁死问题</strong>。由于非正常关闭（如强杀进程），导致 Kafka 无法执行 Graceful Shutdown，底层 LogCleaner 线程在清理 <code>__consumer_offsets</code> 内部状态时报 <code>FileSystemException</code>。 我通过排查源码和日志，发现不仅是文件锁，Zookeeper 中的 Session 也存在假死（Ephemeral Node 残留）导致 <code>NodeExistsException</code>。 最终我通过清理 <code>.lock</code> 锁文件、重置 <code>meta.properties</code> 以及配置调整解决了问题。这也让我深刻理解了中间件环境一致性的重要性，所以在部署阶段，我立刻主导将所有中间件（Kafka/Redis/ES/MinIO）全部切换为 <strong>Docker Compose 容器化部署</strong>，彻底根除了跨平台文件系统差异带来的隐患。”</li></ul>',2)])])}const f=o(s,[["render",n]]);export{p as __pageData,f as default};
